;WITH school AS 
(
	SELECT 
		s.SchoolId,
		s.LocalEducationAgencyId,
		std.SchoolTypeDescriptorId
	FROM #school s
	JOIN edfi.Descriptor d
		ON s.SchoolTypeCodeValue = d.CodeValue
		AND s.SchoolTypeNamespace = d.Namespace
	JOIN edfi.SchoolTypeDescriptor std
		ON d.DescriptorId = std.SchoolTypeDescriptorId
	JOIN edfi.EducationOrganization eo
		ON s.SchoolId = eo.EducationOrganizationId
)
MERGE INTO edfi.School AS tgt
USING school AS src 
	ON tgt.SchoolId = src.SchoolId
WHEN NOT MATCHED THEN 
	INSERT (SchoolId, SchoolTypeDescriptorId, LocalEducationAgencyId)
	VALUES (src.SchoolId, src.SchoolTypeDescriptorId, src.LocalEducationAgencyId)
WHEN MATCHED AND 
	(NULLIF(src.SchoolTypeDescriptorId, tgt.SchoolTypeDescriptorId) IS NOT NULL
	OR NULLIF(tgt.SchoolTypeDescriptorId, src.SchoolTypeDescriptorId) IS NOT NULL
	OR NULLIF(src.LocalEducationAgencyId, tgt.LocalEducationAgencyId) IS NOT NULL
	OR NULLIF(tgt.LocalEducationAgencyId, src.LocalEducationAgencyId) IS NOT NULL
	)
	THEN UPDATE SET 
		tgt.SchoolTypeDescriptorId = src.SchoolTypeDescriptorId,
		tgt.LocalEducationAgencyId = src.LocalEducationAgencyId
;


DROP TABLE #school
SET NOCOUNT OFF;